/* Source: Generated by ChatGPT */
package com.example.cydcompanion.data

import com.example.cydcompanion.domain.ConnectionState
import com.example.cydcompanion.domain.ConsoleLine
import com.example.cydcompanion.domain.SessionSummary
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.flow
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale
import kotlin.random.Random

class FakeCydRepository {

    private val _conn = MutableStateFlow(
        ConnectionState(status = ConnectionState.Status.SCANNING, deviceName = "CYD-NEON")
    )
    val connection: Flow<ConnectionState> = _conn

    val sessions: Flow<List<SessionSummary>> = flow {
        val seed = listOf(
            SessionSummary("run_001", "2026-02-16 07:12", 1284, 3, "Baseline pass"),
            SessionSummary("run_002", "2026-02-16 07:48", 904, 0, "Clean"),
            SessionSummary("run_003", "2026-02-16 08:05", 2211, 7, "Spicy signal soup")
        )
        emit(seed)
    }

    val console: Flow<ConsoleLine> = flow {
        val sdf = SimpleDateFormat("HH:mm:ss.SSS", Locale.US)
        var i = 0
        while (true) {
            delay(180)
            i++
            val lvl = when {
                i % 29 == 0 -> ConsoleLine.Level.ERROR
                i % 11 == 0 -> ConsoleLine.Level.WARN
                else -> ConsoleLine.Level.INFO
            }
            val tag = listOf("CYD", "BLE", "UI", "CAP", "SYS").random()
            val msg = when (lvl) {
                ConsoleLine.Level.INFO -> listOf(
                    "Heartbeat OK",
                    "Frame parsed",
                    "Queue depth=${'$'}{Random.nextInt(0, 12)}",
                    "RX bytes +${'$'}{Random.nextInt(20, 240)}",
                    "Touch preset locked: #5"
                ).random()
                ConsoleLine.Level.WARN -> listOf(
                    "RSSI wobble detected",
                    "Retrying write",
                    "Dropped frame (simulated)",
                    "Clock drift +2ms"
                ).random()
                ConsoleLine.Level.ERROR -> listOf(
                    "Simulated fault: CRC mismatch",
                    "Simulated fault: buffer overrun",
                    "Simulated fault: stale session"
                ).random()
            }
            emit(ConsoleLine(ts = sdf.format(Date()), level = lvl, tag = tag, msg = msg))
        }
    }

    suspend fun simulateConnectionCycle() {
        _conn.emit(ConnectionState(ConnectionState.Status.SCANNING, "CYD-NEON"))
        delay(900)
        _conn.emit(ConnectionState(ConnectionState.Status.CONNECTING, "CYD-NEON"))
        delay(1200)
        _conn.emit(ConnectionState(ConnectionState.Status.CONNECTED, "CYD-NEON", rssi = -53, mtu = 185, uptimeSec = 42))

        // jitter
        var up = 42
        while (true) {
            delay(1200)
            up += 1
            _conn.emit(ConnectionState(ConnectionState.Status.CONNECTED, "CYD-NEON", rssi = -48 - Random.nextInt(0, 18), mtu = 185, uptimeSec = up))
        }
    }
}
