package com.example.cydcompanion.ui

import androidx.compose.foundation.layout.Box
import androidx.compose.foundation.layout.fillMaxSize
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.Analytics
import androidx.compose.material.icons.filled.CloudUpload
import androidx.compose.material.icons.filled.Gamepad
import androidx.compose.material.icons.filled.PlayArrow
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Modifier
import androidx.navigation.compose.*
import com.example.cydcompanion.data.FakeCydRepository
import com.example.cydcompanion.ui.background.TokyoNeonBackdrop
import kotlinx.coroutines.launch

private sealed class Tab(val route: String, val label: String, val icon: @Composable () -> Unit) {
    data object Live : Tab("live", "Live", { Icon(Icons.Filled.PlayArrow, contentDescription = null) })
    data object Analyze : Tab("analyze", "Analyze", { Icon(Icons.Filled.Analytics, contentDescription = null) })
    data object Control : Tab("control", "Control", { Icon(Icons.Filled.Gamepad, contentDescription = null) })
    data object Export : Tab("export", "Export", { Icon(Icons.Filled.CloudUpload, contentDescription = null) })
}

@Composable
fun AppRoot() {
    val nav = rememberNavController()
    val repo = remember { FakeCydRepository() }
    val scope = rememberCoroutineScope()

    LaunchedEffect(Unit) {
        scope.launch { repo.simulateConnectionCycle() }
    }

    val tabs = listOf(Tab.Live, Tab.Analyze, Tab.Control, Tab.Export)

    TokyoNeonBackdrop {
        Scaffold(
            containerColor = MaterialTheme.colorScheme.background.copy(alpha = 0.0f),
            bottomBar = {
                NavigationBar(
                    containerColor = MaterialTheme.colorScheme.surface.copy(alpha = 0.55f),
                    tonalElevation = 0.dp
                ) {
                    val current by nav.currentBackStackEntryAsState()
                    val route = current?.destination?.route
                    tabs.forEach { tab ->
                        NavigationBarItem(
                            selected = route == tab.route,
                            onClick = { nav.navigate(tab.route) { launchSingleTop = true } },
                            icon = tab.icon,
                            label = { Text(tab.label) }
                        )
                    }
                }
            }
        ) { padding ->
            Box(modifier = Modifier.fillMaxSize()) {
                NavHost(navController = nav, startDestination = Tab.Live.route) {
                    composable(Tab.Live.route) { LiveScreen(repo = repo) }
                    composable(Tab.Analyze.route) { AnalyzeScreen(repo = repo) }
                    composable(Tab.Control.route) { ControlScreen(repo = repo) }
                    composable(Tab.Export.route) { ExportScreen(repo = repo) }
                }
            }
        }
    }
}
