@Composable
fun LiveScreen(repo: FakeCydRepository) {
    val conn by produceState<ConnectionState>(
        initialValue = ConnectionState(ConnectionState.Status.SCANNING, "CYD-NEON")
    ) {
        repo.connection.collectLatest { value = it }
    }

    val lines = remember { mutableStateListOf<ConsoleLine>() }
    LaunchedEffect(Unit) {
        repo.console.collectLatest {
            if (lines.size > 240) lines.removeRange(0, 40)
            lines.add(it)
        }
    }

    ScreenScaffold(title = "LIVE LINK") {
        NeonCard {
            Column(Modifier.fillMaxWidth()) {
                Text("CYD STATUS", style = MaterialTheme.typography.titleMedium)
                Spacer(Modifier.height(8.dp))

                val status = conn.status
                val statusText = when (status) {
                    ConnectionState.Status.DISCONNECTED -> "DISCONNECTED"
                    ConnectionState.Status.SCANNING -> "SCANNING…"
                    ConnectionState.Status.CONNECTING -> "CONNECTING…"
                    ConnectionState.Status.CONNECTED -> "CONNECTED"
                }
                Text(statusText, style = MaterialTheme.typography.headlineSmall)

                Spacer(Modifier.height(8.dp))
                Row(horizontalArrangement = Arrangement.spacedBy(10.dp)) {
                    AssistChip(onClick = {}, label = { Text(conn.deviceName ?: "—") })
                    AssistChip(onClick = {}, label = { Text("RSSI ${'$'}{conn.rssi ?: "—"}") })
                    AssistChip(onClick = {}, label = { Text("MTU ${'$'}{conn.mtu ?: "—"}") })
                    AssistChip(onClick = {}, label = { Text("UP ${'$'}{conn.uptimeSec ?: 0}s") })
                }

                Spacer(Modifier.height(12.dp))
                Row(horizontalArrangement = Arrangement.spacedBy(12.dp)) {
                    NeonButton(text = "START", onClick = {})
                    NeonButton(text = "STOP", onClick = {}, isDanger = true)
                }
            }
        }

        Spacer(Modifier.height(14.dp))

        NeonCard {
            Column(Modifier.fillMaxWidth()) {
                Text("CONSOLE", style = MaterialTheme.typography.titleMedium)
                Spacer(Modifier.height(8.dp))
                LazyColumn(
                    modifier = Modifier
                        .fillMaxWidth()
                        .heightIn(min = 220.dp, max = 520.dp)
                ) {
                    itemsIndexed(lines) { _, line ->
                        val prefix = "[${'$'}{line.ts}] ${'$'}{line.level} ${'$'}{line.tag}: "
                        Text(
                            text = prefix + line.msg,
                            style = MaterialTheme.typography.bodySmall,
                            fontFamily = FontFamily.Monospace
                        )
                    }
                }
            }
        }
    }
}
