package com.example.cydcompanion.ui.theme

import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.darkColorScheme
import androidx.compose.runtime.Composable
import androidx.compose.ui.graphics.Color

private val TokyoNeon = darkColorScheme(
    background = Color(0xFF05040A),   // inky
    surface = Color(0xFF0B0A14),      // deep indigo
    primary = Color(0xFF00E5FF),      // neon cyan
    secondary = Color(0xFFFF2BD6),    // neon magenta
    tertiary = Color(0xFF8A5CFF),     // violet glow
    outline = Color(0xFF2C2A3A),
    error = Color(0xFFFF3B3B)
)

@Composable
fun TokyoNeonTheme(content: @Composable () -> Unit) {
